# =======================================================
# Root privileges check
# =======================================================
if [ "$(id -u)" -ne 0 ]; then
    exec sudo -- "$0" "$@"
fi

# =======================================================
# Variables
# =======================================================
CURR_TTY="/dev/tty1"
RTL_BT="/lib/firmware/rtl_bt"
RTL8723BU_B64=""

# =======================================================
# Display Management
# =======================================================
printf "\e[?25l" >> "$CURR_TTY"
dialog --clear
printf "\033[H\033[2J" >> "$CURR_TTY"
printf "Installing driver, please wait...\n" >> "$CURR_TTY"
sleep 0.5

# =======================================================
# Main Execution
# =======================================================
mkdir -p $RTL_BT

printf '%s' "$RTL8723BU_B64" | base64 -d > $RTL_BT/rtl8723b_fw.bin
chmod 644 $RTL_BT/rtl8723b_fw.bin

[[ ! -f "$RTL_BT/rtl8723b_fw.bin" ]] && printf "Failed, exiting." >> "$CURR_TTY" && exit 1

printf "Success! Rebooting in 3 seconds..." >> "$CURR_TTY"
sleep 3
reboot